    if (!PyArg_ParseTuple(args, "OO", &weights_list, &cov_list))
        return NULL;

    Py_ssize_t n = PyList_Size(weights_list);

    // Extract weights into a C array
    double *w = (double *)malloc(n * sizeof(double));
    for (Py_ssize_t i = 0; i < n; i++) {
        PyObject *item = PyList_GetItem(weights_list, i);
        w[i] = PyFloat_AsDouble(item);
    }

    // Extract covariance matrix into a flat C array
    double *cov = (double *)malloc(n * n * sizeof(double));
    for (Py_ssize_t i = 0; i < n; i++) {
        PyObject *row = PyList_GetItem(cov_list, i);
        for (Py_ssize_t j = 0; j < n; j++) {
            PyObject *item = PyList_GetItem(row, j);
            cov[i * n + j] = PyFloat_AsDouble(item);
        }
    }

    // Step 1: Calculate S * x (matrix-vector multiply)
